import{_ as t,o as a,c as s,aA as i}from"./chunks/framework.DyaeLj5o.js";const u=JSON.parse('{"title":"EyeTracking Data Structures","description":"","frontmatter":{},"headers":[],"relativePath":"explanations/data-structures.md","filePath":"explanations/data-structures.md","lastUpdated":null}'),n={name:"explanations/data-structures.md"};function o(r,e,l,d,c,p){return a(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="EyeTracking-Data-Structures" tabindex="-1">EyeTracking Data Structures <a class="header-anchor" href="#EyeTracking-Data-Structures" aria-label="Permalink to &quot;EyeTracking Data Structures {#EyeTracking-Data-Structures}&quot;">​</a></h1><p>Understanding <code>EyeFun.jl</code>&#39;s core data structures and how they leverage Julia&#39;s type system.</p><h2 id="Julia-Types-and-Multiple-Dispatch" tabindex="-1">Julia Types &amp; Multiple Dispatch <a class="header-anchor" href="#Julia-Types-and-Multiple-Dispatch" aria-label="Permalink to &quot;Julia Types &amp;amp; Multiple Dispatch {#Julia-Types-and-Multiple-Dispatch}&quot;">​</a></h2><p>If you&#39;re coming from Python or MATLAB, Julia&#39;s type system works a little differently. The full details are in the <a href="https://docs.julialang.org/en/v1/manual/types/" target="_blank" rel="noreferrer">Julia documentation</a>, but the key idea for everyday <code>EyeFun.jl</code> use is <strong>multiple dispatch</strong>.</p><p>This means a function can have the same name but do different things depending on the <em>type</em> of data passed to it:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Same function, different file formats → different internal parsing behaviour</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">read_et_data</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(EDFFile, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;data.edf&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">read_et_data</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(SMIFile, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;data.idf&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>If you are ever unsure what type a variable is, use <code>typeof()</code>:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">typeof</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(dat)   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># e.g. EyeFun.EyeData</span></span></code></pre></div><h3 id="Abstract-vs-Concrete-Types" tabindex="-1">Abstract vs Concrete Types <a class="header-anchor" href="#Abstract-vs-Concrete-Types" aria-label="Permalink to &quot;Abstract vs Concrete Types {#Abstract-vs-Concrete-Types}&quot;">​</a></h3><p>Julia distinguishes between <strong>concrete</strong> and <strong>abstract</strong> types:</p><ul><li><p><strong>Concrete types</strong> are the actual data structures you create and work with — for example <code>EyeData</code>, <code>EDFFile</code>, or <code>RectAOI</code>. These hold real data.</p></li><li><p><strong>Abstract types</strong> are categories or groupings — you can never create one directly, but they let functions accept a <em>family</em> of related types. For example, <code>EyeFile</code> is abstract; it simply stands for &quot;any supported eye-tracking file format&quot;.</p></li></ul><hr><h2 id="Type-Hierarchy" tabindex="-1">Type Hierarchy <a class="header-anchor" href="#Type-Hierarchy" aria-label="Permalink to &quot;Type Hierarchy {#Type-Hierarchy}&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Any</span></span>
<span class="line"><span>├── EyeFile (abstract) - Representation of raw files</span></span>
<span class="line"><span>│   ├── EDFFile</span></span>
<span class="line"><span>│   ├── SMIFile</span></span>
<span class="line"><span>│   └── TobiiFile</span></span>
<span class="line"><span>├── EyeData - Processed and unified continuous data</span></span>
<span class="line"><span>└── AOI (abstract) - Spatial Areas of Interest</span></span>
<span class="line"><span>    ├── RectAOI</span></span>
<span class="line"><span>    ├── CircleAOI</span></span>
<span class="line"><span>    ├── EllipseAOI</span></span>
<span class="line"><span>    └── PolygonAOI</span></span></code></pre></div><p>See the <a href="./../reference/types">Types Reference</a> for full field-by-field documentation of each type.</p><h2 id="EyeFile-Format-Specs" tabindex="-1"><code>EyeFile</code> (Format Specs) <a class="header-anchor" href="#EyeFile-Format-Specs" aria-label="Permalink to &quot;\`EyeFile\` (Format Specs) {#EyeFile-Format-Specs}&quot;">​</a></h2><p>The <code>EyeFile</code> types (<code>EDFFile</code>, <code>SMIFile</code>, <code>TobiiFile</code>) are structural types used during parsing. <code>read_et_data</code> automatically dispatches on the file extension to read the raw proprietary components utilizing these types before automatically packaging everything into the singular <code>EyeData</code> object.</p><h2 id="EyeData" tabindex="-1"><code>EyeData</code> <a class="header-anchor" href="#EyeData" aria-label="Permalink to &quot;\`EyeData\` {#EyeData}&quot;">​</a></h2><p>The central data structure you will work with. <code>EyeData</code> wraps a wide <code>DataFrame</code> with one row per sample, interpolating parsed discrete events across the continuous time series.</p><table tabindex="0"><thead><tr><th style="text-align:right;">Field</th><th style="text-align:right;">Type</th><th style="text-align:right;">Description</th></tr></thead><tbody><tr><td style="text-align:right;"><code>df</code></td><td style="text-align:right;"><code>DataFrame</code></td><td style="text-align:right;">The continuous data (time × variables)</td></tr><tr><td style="text-align:right;"><code>source</code></td><td style="text-align:right;"><code>String</code></td><td style="text-align:right;">Source filename</td></tr><tr><td style="text-align:right;"><code>sample_rate</code></td><td style="text-align:right;"><code>Float64</code></td><td style="text-align:right;">Sampling frequency in Hz</td></tr><tr><td style="text-align:right;"><code>screen_res</code></td><td style="text-align:right;"><code>Tuple{Float64, Float64}</code></td><td style="text-align:right;">Display resolution (width, height)</td></tr><tr><td style="text-align:right;"><code>screen_width_cm</code></td><td style="text-align:right;"><code>Float64</code></td><td style="text-align:right;">Physical monitor width</td></tr><tr><td style="text-align:right;"><code>viewing_distance_cm</code></td><td style="text-align:right;"><code>Float64</code></td><td style="text-align:right;">Distance from participant to screen</td></tr></tbody></table><h3 id="Continuous-DataFrame-df-columns" tabindex="-1">Continuous DataFrame (<code>df</code>) columns <a class="header-anchor" href="#Continuous-DataFrame-df-columns" aria-label="Permalink to &quot;Continuous DataFrame (\`df\`) columns {#Continuous-DataFrame-df-columns}&quot;">​</a></h3><p>The underlying <code>df</code> contains continuous gaze coordinates (<code>gx</code>, <code>gy</code>), pupil sizes (<code>pa</code>), and binary state masks annotating whether the sample occurred during a specific event category (<code>in_fix</code>, <code>in_sacc</code>, <code>in_blink</code>). It also contains dynamic string annotations like <code>message</code> when system triggers appear on the timeline.</p><h2 id="AOI" tabindex="-1"><code>AOI</code> <a class="header-anchor" href="#AOI" aria-label="Permalink to &quot;\`AOI\` {#AOI}&quot;">​</a></h2><p>Areas of Interest define spatial boundaries on the stimulus screen to extract semantic gaze metrics.</p><table tabindex="0"><thead><tr><th style="text-align:right;">Concrete Type</th><th style="text-align:right;">Primitive Fields</th></tr></thead><tbody><tr><td style="text-align:right;"><code>RectAOI</code></td><td style="text-align:right;"><code>x</code>, <code>y</code>, <code>width</code>, <code>height</code></td></tr><tr><td style="text-align:right;"><code>CircleAOI</code></td><td style="text-align:right;"><code>x</code>, <code>y</code>, <code>radius</code></td></tr><tr><td style="text-align:right;"><code>EllipseAOI</code></td><td style="text-align:right;"><code>x</code>, <code>y</code>, <code>radius_x</code>, <code>radius_y</code></td></tr><tr><td style="text-align:right;"><code>PolygonAOI</code></td><td style="text-align:right;"><code>points::Vector{Tuple{Float64, Float64}}</code></td></tr></tbody></table><h2 id="Data-Flow" tabindex="-1">Data Flow <a class="header-anchor" href="#Data-Flow" aria-label="Permalink to &quot;Data Flow {#Data-Flow}&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Raw Eye-Tracking File (.edf, .idf, .tsv)</span></span>
<span class="line"><span>    ↓ read_et_data()</span></span>
<span class="line"><span>EyeData</span></span>
<span class="line"><span>    ↓ (pupil processing, drift correction, event detection...)</span></span>
<span class="line"><span>EyeData (cleaned)</span></span>
<span class="line"><span>    ↓ fixation_metrics() / aoi_metrics() / group_summary()</span></span>
<span class="line"><span>DataFrame (Aggregated Statistics)</span></span></code></pre></div>`,27)])])}const y=t(n,[["render",o]]);export{u as __pageData,y as default};
